from collections import deque
from typing import List

class Solution:
    def shortestAlternatingPaths(self, n: int, redEdges: List[List[int]], blueEdges: List[List[int]]) -> List[int]:
        red = [[] for _ in range(n)]
        blue = [[] for _ in range(n)]
        for a, b in redEdges:
            red[a].append(b)
        for u, v in blueEdges:
            blue[u].append(v)

        ans = [-1] * n
        visited = set()
        q = deque([(0, 0, None)])  # (node, steps, last_color)
        visited.add((0, None))

        while q:
            node, steps, last_color = q.popleft()
            if ans[node] == -1 or steps < ans[node]:
                ans[node] = steps

            if last_color != 'red':
                for neighbor in red[node]:
                    if (neighbor, 'red') not in visited:
                        visited.add((neighbor, 'red'))
                        q.append((neighbor, steps + 1, 'red'))
            if last_color != 'blue':
                for neighbor in blue[node]:
                    if (neighbor, 'blue') not in visited:
                        visited.add((neighbor, 'blue'))
                        q.append((neighbor, steps + 1, 'blue'))

        return ans
```
